const items = $input.all();

// Filtrer ET mapper en une seule opération
const donnees = items

    .map(item => {
        const row = item.json;
        return {
            msg_blocage: "Liste Bons de commande Sans Pièces Jointes " + row.NUM_0,
            service: "SRV001",
            code_salarie: ""
        };
    });

return [{
    json: {
        donnees: JSON.stringify(donnees),  // ← stringify it here
        email_expediteur: "astitoumde@gmail.com",
        headless: false
    }
}];

